fn fib(n: i64) -> i64 {
    if n <= 1 {
        n
    } else {
        fib(n - 1) + fib(n - 2)
    }
}

fn main() {
    for i in 0..10 {
        print(f"fib({i}) = ");
        println(fib(i));
    }
}

// Test while-let pattern matching loops with Option types

fn countdown(n: i64) -> Option<i64> {
    if n > 0 {
        Some(n - 1)
    } else {
        let none: Option<i64> = None;
        none
    }
}

fn main() -> i64 {
    // Basic while-let: iterate until None
    var opt: Option<i64> = Some(3);
    while let Some(x) = opt {
        println(x);
        opt = countdown(x);
    }

    // Early exit with break
    var opt2: Option<i64> = Some(10);
    while let Some(x) = opt2 {
        if x < 8 {
            break;
        }
        println(x);
        opt2 = countdown(x);
    }
    println("done");

    return 0;
}

enum Shape {
    Circle(i64);
    Rectangle(i64, i64);
    Triangle(i64, i64);
}

fn area(shape: Shape) -> i64 {
    match shape {
        Circle(r) => r * r * 3,
        Rectangle(w, h) => w * h,
        Triangle(b, h) => b * h / 2,
    }
}

fn main() {
    let c = Circle(5);
    let r = Rectangle(4, 6);
    let t = Triangle(3, 8);

    print("Circle area: ");
    println(area(c));
    print("Rectangle area: ");
    println(area(r));
    // Or using inline interpolation
    println(f"Triangle area: {area(t)}");
}

actor Counter {
    var count: i64;

    receive fn increment(n: i64) -> i64 {
        count = count + n;
        print("Count is now: ");
        println(count);
        count
    }
}

fn main() {
    let c = spawn Counter(count: 0);
    await c.increment(5);
    await c.increment(3);
    match await c.increment(12) {
        Ok(total) => println(f"Final total: {total}"),
        Err(_) => println("send failed"),
    }
}

// Spawn several actors and send each a message with `await`.
// Each actor runs on its own task and replies independently.

actor Worker {
    let id: i64;

    receive fn handle(task: i64) -> i64 {
        println(f"Worker {id} handling task {task}");
        task * 2
    }
}

fn main() {
    let w1 = spawn Worker(id: 1);
    let w2 = spawn Worker(id: 2);
    await w1.handle(10);
    await w2.handle(20);
    await w1.handle(30);
}

// Hew handles concurrency with actors and `await`.
// `await` sends a message to an actor and waits for its reply.

actor Calculator {
    var total: i64;

    receive fn add(n: i64) -> i64 {
        total = total + n;
        println(f"running total: {total}");
        total
    }
}

fn main() {
    let calc = spawn Calculator(total: 0);
    await calc.add(10);
    await calc.add(20);
    await calc.add(12);
    println("done");
}

machine Light {
    events { Toggle; }
    state Off;
    state On;
    on Toggle: Off => On;
    on Toggle: On => Off;
}

fn main() -> i64 {
    var light = Light::Off;
    println(light.state_name());
    light.step(Toggle);
    println(light.state_name());
    light.step(Toggle);
    println(light.state_name());
    0
}

