enum Direction {
    North;
    South;
    East;
    West;
}

fn describe(dir: Direction) -> string {
    match dir {
        North => "heading north",
        South => "heading south",
        East => "heading east",
        West => "heading west",
    }
}

fn main() {
    let dir = North;
    println(describe(dir));
    println(describe(South));
}

fn divide(a: i64, b: i64) -> Option<i64> {
    if b == 0 {
        None
    } else {
        Some(a / b)
    }
}

fn main() {
    match divide(10, 3) {
        Some(result) => println(f"10 / 3 = {result}"),
        None => println("cannot divide by zero"),
    }

    match divide(10, 0) {
        Some(result) => println(f"10 / 0 = {result}"),
        None => println("cannot divide by zero"),
    }
}

fn double(x: i64) -> i64 { x * 2 }
fn square(x: i64) -> i64 { x * x }

fn apply(f: fn(i64) -> i64, x: i64) -> i64 {
    f(x)
}

fn main() {
    println(f"double(5) = {apply(double, 5)}");
    println(f"square(4) = {apply(square, 4)}");
}

actor Worker {
    let id: i64;

    receive fn work(x: i64) -> i64 {
        println(f"Worker {id} processing {x}");
        x * 2
    }
}

// A supervisor starts and restarts a tree of child actors.
supervisor WorkerPool {
    strategy: one_for_one;
    intensity: 5 within 60s;
    child w1: Worker(id: 1);
    child w2: Worker(id: 2);
}

fn main() {
    let workers = spawn WorkerPool;
    let w1 = workers.w1;
    await w1.work(10);
    let w2 = workers.w2;
    await w2.work(20);
}
